solutions.javascript:
var sumOfEncryptedInt = function(nums) {
    let total = 0;
    for (const x of nums) {
        const s = String(x);
        const md = s.split('').reduce((a, b) => a > b ? a : b);
        total += parseInt(md.repeat(s.length));
    }
    return total;
};
